<span class="line"><span style="color:#CDD6F4;">    fmt</span><span style="color:#9399B2;">.</span><span style="color:#89B4FA;font-style:italic;">Println</span><span style="color:#9399B2;">(</span><span style="color:#CDD6F4;">format</span><span style="color:#9399B2;">.</span><span style="color:#89B4FA;font-style:italic;">FormatOutput</span><span style="color:#9399B2;">(</span><span style="color:#CDD6F4;">content</span><span style="color:#9399B2;">,</span><span style="color:#CDD6F4;"> outputFormat</span><span style="color:#9399B2;">))</span></span>
